@tailwind base;
@tailwind components;
@tailwind utilities;

/* LIGHT MODE */
:root {
  --button-outline: rgba(0,0,0, .10);
  --badge-outline: rgba(0,0,0, .05);
  --opaque-button-border-intensity: -8;
  --elevate-1: rgba(0,0,0, .03);
  --elevate-2: rgba(0,0,0, .08);
  --background: 240 5% 96%;
  --foreground: 240 6% 10%;
  --border: 240 6% 88%;
  --card: 240 5% 94%;
  --card-foreground: 240 6% 12%;
  --card-border: 240 5% 90%;
  --sidebar: 240 5% 92%;
  --sidebar-foreground: 240 6% 14%;
  --sidebar-border: 240 5% 86%;
  --sidebar-primary: 262 83% 58%;
  --sidebar-primary-foreground: 262 15% 98%;
  --sidebar-accent: 240 8% 84%;
  --sidebar-accent-foreground: 240 6% 18%;
  --sidebar-ring: 262 83% 58%;
  --popover: 240 6% 90%;
  --popover-foreground: 240 6% 16%;
  --popover-border: 240 6% 84%;
  --primary: 262 83% 58%;
  --primary-foreground: 262 15% 98%;
  --secondary: 240 8% 86%;
  --secondary-foreground: 240 6% 18%;
  --muted: 240 8% 88%;
  --muted-foreground: 240 5% 40%;
  --accent: 240 10% 90%;
  --accent-foreground: 240 6% 16%;
  --destructive: 0 84% 42%;
  --destructive-foreground: 0 10% 98%;
  --input: 240 8% 78%;
  --ring: 262 83% 58%;
  --chart-1: 262 70% 48%;
  --chart-2: 280 65% 52%;
  --chart-3: 200 70% 45%;
  --chart-4: 340 75% 50%;
  --chart-5: 30 80% 48%;
  --font-sans: Inter, system-ui, sans-serif;
  --font-serif: Georgia, serif;
  --font-mono: JetBrains Mono, monospace;
  --radius: .5rem;

  /* 7D/8D Movie Effects */
  --glass-blur: 12px;
  --glass-opacity: 0.7;
  --depth-z-1: 10px;
  --depth-z-2: 20px;
  --depth-z-3: 30px;
  --shadow-2xs: 0px 2px 0px 0px hsl(240 5% 20% / 0.02);
