  --shadow-xl: 0px 2px 0px 0px hsl(240 5% 0% / 0.50), 0px 8px 10px -1px hsl(240 5% 0% / 0.55);
  --shadow-2xl: 0px 2px 0px 0px hsl(240 5% 0% / 0.60);

/* Fallback for older browsers */
  --sidebar-primary-border: hsl(var(--sidebar-primary));
