import { useQuery } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { Loader2, ChevronLeft, Eye, BookOpen, Zap, Heart, Trash2, Copy } from "lucide-react";

export default function WebsiteMenu() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  // Fetch all websites
  const { data: websites = [], isLoading } = useQuery({
    queryKey: ["/api/websites"],
    queryFn: async () => {
      const res = await apiRequest("GET", "/api/websites");
      return res.json();
    },
  });

  const handleDelete = async (id: string) => {
    try {
      await apiRequest("DELETE", `/api/websites/${id}`);
      toast({
        title: "Deleted",
        description: "Website removed successfully.",
      });
      // Refetch websites
      window.location.reload();
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to delete website",
        variant: "destructive",
      });
    }
  };

  const handleFavorite = async (id: string, isFavorite: boolean) => {
    try {
      await apiRequest("PATCH", `/api/websites/${id}`, { isFavorite: !isFavorite });
      window.location.reload();
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to toggle favorite",
        variant: "destructive",
      });
    }
  };

  const handleCopy = (code: string) => {
    navigator.clipboard.writeText(code);
    toast({
      title: "Copied",
      description: "Code copied to clipboard",
    });
  };

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="border-b border-border/50 bg-background/50 backdrop-blur-sm sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLocation("/website-generator")}
              data-testid="button-back"
            >
              <ChevronLeft className="h-5 w-5" />
            </Button>
            <h1 className="text-2xl font-bold text-center flex-1">Website Features</h1>
            <div className="w-10" />
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : websites.length === 0 ? (
          <Card className="p-12 text-center text-muted-foreground">
            <p className="mb-4">No websites created yet</p>
            <Button onClick={() => setLocation("/website-generator")}>
              Go to Generator
            </Button>
          </Card>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {websites.map((website: any) => (
              <Card key={website.id} className="p-6 flex flex-col gap-4 hover-elevate">
                <div>
                  <h3 className="font-semibold text-lg mb-2 truncate">{website.title}</h3>
                  <p className="text-sm text-muted-foreground line-clamp-2">{website.description}</p>
                </div>

                {/* Feature Buttons */}
                <div className="space-y-2 flex-1">
                  <Button
                    variant="outline"
                    size="sm"
                    className="w-full justify-start hover-elevate active-elevate-2"
                    onClick={() => setLocation(`/view/${website.id}`)}
                    data-testid={`button-view-${website.id}`}
                  >
                    <Eye className="h-4 w-4 mr-2" />
                    View Live
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    className="w-full justify-start hover-elevate active-elevate-2"
                    onClick={() => setLocation(`/website-learn/${website.id}`)}
                    data-testid={`button-learn-${website.id}`}
                  >
                    <BookOpen className="h-4 w-4 mr-2" />
                    Learn Code
                  </Button>
                </div>

                {/* Management Buttons */}
                <div className="border-t pt-3 flex gap-2">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => handleFavorite(website.id, website.isFavorite)}
                    className="hover-elevate active-elevate-2"
                    data-testid={`button-favorite-${website.id}`}
                  >
                    <Heart className={`h-4 w-4 ${website.isFavorite ? "fill-red-500 text-red-500" : ""}`} />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => handleCopy(website.htmlCode)}
                    className="hover-elevate active-elevate-2"
                    data-testid={`button-copy-${website.id}`}
                  >
                    <Copy className="h-4 w-4" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => handleDelete(website.id)}
                    className="hover-elevate active-elevate-2 text-destructive ml-auto"
                    data-testid={`button-delete-${website.id}`}
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </div>
              </Card>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

client/src/pages/ImageGallery.tsx.content:
import { useState } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { useLocation } from "wouter";
import { useToast } from "@/hooks/use-toast";
import { ThemeToggle } from "@/components/ThemeToggle";
import { ArrowLeft, Download, Trash2, Loader2, Image as ImageIcon } from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { GeneratedImage } from "@shared/schema";

export default function ImageGallery() {
  const [, setLocation] = useLocation();
  const [selectedImage, setSelectedImage] = useState<GeneratedImage | null>(null);
  const { toast } = useToast();

  const { data: images = [], isLoading } = useQuery<GeneratedImage[]>({
    queryKey: ["/api/generated-images"],
  });

  const handleDeleteImage = async (imageId: string) => {
    try {
      const response = await apiRequest("DELETE", `/api/generated-images/${imageId}`);
      await response.json();
      queryClient.invalidateQueries({ queryKey: ["/api/generated-images"] });
      setSelectedImage(null);
      toast({ title: "Image deleted", description: "Image removed from gallery" });
    } catch (error) {
      toast({ title: "Error", description: "Failed to delete image", variant: "destructive" });
    }
  };

  const downloadImage = async (imageUrl: string, prompt: string) => {
    try {
      const response = await fetch(imageUrl);
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `image-${prompt.substring(0, 20)}-${Date.now()}.png`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
    } catch (error) {
      console.error("Download failed:", error);
    }
  };

  return (
    <div className="h-screen flex flex-col bg-background">
      {/* Header */}
      <header className="border-b border-border/50 bg-background/50 backdrop-blur-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLocation("/chat")}
              className="hover-elevate active-elevate-2"
              data-testid="button-back"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div>
              <h1 className="text-2xl font-bold">Image Gallery</h1>
              <p className="text-sm text-muted-foreground">
                {images.length} {images.length === 1 ? "image" : "images"} generated
              </p>
            </div>
          </div>
          <ThemeToggle />
        </div>
      </header>

      {/* Gallery Content */}
      <div className="flex-1 overflow-y-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : images.length === 0 ? (
            <div className="text-center py-12">
              <ImageIcon className="h-16 w-16 mx-auto mb-4 text-muted-foreground" />
              <h2 className="text-xl font-semibold mb-2">No images yet</h2>
              <p className="text-muted-foreground mb-6">
                Generate images by clicking "Create Image" in the Chat
              </p>
              <Button
                onClick={() => setLocation("/chat")}
                className="hover-elevate active-elevate-2"
              >
                Go to Chat
              </Button>
            </div>
          ) : selectedImage ? (
            // Image Detail View
            <div className="max-w-3xl mx-auto">
              <Button
                variant="outline"
                size="sm"
                onClick={() => setSelectedImage(null)}
                className="mb-4 hover-elevate active-elevate-2"
              >
                <ArrowLeft className="h-4 w-4 mr-2" />
                Back to Gallery
              </Button>

              <Card className="p-6 space-y-4">
                <div className="rounded-lg overflow-hidden border border-border/50 bg-muted">
                  <img
                    src={selectedImage.imageUrl}
                    alt={selectedImage.prompt}
                    className="w-full h-auto max-h-96 object-contain"
                    data-testid={`img-detail-${selectedImage.id}`}
                    loading="lazy"
                  />
                </div>

                <div className="space-y-2">
                  <h2 className="text-lg font-semibold">Description</h2>
                  <p className="text-muted-foreground">{selectedImage.prompt}</p>
                </div>

                {selectedImage.relatedTopic && (
                  <div className="space-y-2">
                    <h2 className="text-lg font-semibold">Topic</h2>
                    <p className="text-muted-foreground">{selectedImage.relatedTopic}</p>
                  </div>
                )}

                <div className="space-y-2">
                  <h2 className="text-lg font-semibold">Generated</h2>
                  <p className="text-sm text-muted-foreground">
                    {new Date(selectedImage.createdAt).toLocaleDateString()} at{" "}
                    {new Date(selectedImage.createdAt).toLocaleTimeString()}
                  </p>
                </div>

                <div className="flex gap-2 pt-4">
                  <Button
                    variant="outline"
                    onClick={() => downloadImage(selectedImage.imageUrl, selectedImage.prompt)}
                    className="flex-1 hover-elevate active-elevate-2"
                    data-testid="button-download-image"
                  >
                    <Download className="h-4 w-4 mr-2" />
                    Download
                  </Button>
                  <Button
                    variant="destructive"
                    onClick={() => handleDeleteImage(selectedImage.id)}
                    className="hover-elevate active-elevate-2"
                    data-testid="button-delete-image"
                  >
                    <Trash2 className="h-4 w-4 mr-2" />
                    Delete
                  </Button>
                </div>
              </Card>
            </div>
          ) : (
            // Gallery Grid
            <div className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {images.map((image) => (
                  <Card
                    key={image.id}
                    className="overflow-hidden cursor-pointer hover-elevate active-elevate-2 transition-opacity group"
                    onClick={() => setSelectedImage(image)}
                    data-testid={`card-image-${image.id}`}
                  >
                    <div className="aspect-square overflow-hidden bg-muted relative">
                      <img
                        src={image.imageUrl}
                        alt={image.prompt}
                        className="w-full h-full object-cover hover:opacity-80 transition-opacity"
                        data-testid={`img-gallery-${image.id}`}
                        loading="lazy"
                      />
                      <Button
                        variant="destructive"
                        size="icon"
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDeleteImage(image.id);
                        }}
                        className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity hover-elevate"
                        data-testid={`button-delete-${image.id}`}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                    <div className="p-3 space-y-2">
                      <p className="text-sm font-medium line-clamp-2">{image.prompt}</p>
                      <p className="text-xs text-muted-foreground">
                        {new Date(image.createdAt).toLocaleDateString()}
                      </p>
                    </div>
                  </Card>
                ))}
              </div>

              <div className="flex justify-center mt-6">
                <Button
                  variant="destructive"
                  onClick={() => {
                    if (confirm("Are you sure you want to delete all images?")) {
                      images.forEach(img => handleDeleteImage(img.id));
                    }
                  }}
                  className="hover-elevate active-elevate-2"
                  data-testid="button-clear-all-images"
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Clear All Images
                </Button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

