import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { useLocation, useParams } from "wouter";
import { apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { Loader2, ChevronLeft, Zap, Send, Copy } from "lucide-react";

interface DebugMessage {
  type: "user" | "status";
  content: string;
}

export default function WebsiteDebug() {
  const [, setLocation] = useLocation();
  const { id } = useParams<{ id: string }>();
  const { toast } = useToast();
  const [debugPrompt, setDebugPrompt] = useState("");
  const [debugHistory, setDebugHistory] = useState<DebugMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [scrollRef, setScrollRef] = useState<HTMLDivElement | null>(null);
  const [activeTab, setActiveTab] = useState<"html" | "css" | "js">("html");
  const [currentCode, setCurrentCode] = useState({
    html: "",
    css: "",
    js: "",
  });

  // Auto-scroll when messages update
  useEffect(() => {
    setTimeout(() => {
      if (scrollRef) {
        scrollRef.scrollTop = scrollRef.scrollHeight;
      }
    }, 100);
  }, [debugHistory]);

  // Fetch website
  const { data: website, isLoading: websiteLoading, refetch } = useQuery({
    queryKey: ["/api/websites", id],
    queryFn: async () => {
      const res = await apiRequest("GET", `/api/websites/${id}`);
      return res.json();
    },
    enabled: !!id,
  });

  // Update local code when website changes
  useEffect(() => {
    if (website) {
      setCurrentCode({
        html: website.htmlCode || "",
        css: website.cssCode || "",
        js: website.jsCode || "",
      });
    }
  }, [website]);

  const handleSubmit = async () => {
    if (!debugPrompt.trim() || isLoading) return;

    const userPrompt = debugPrompt;
    setDebugPrompt("");
    setDebugHistory((prev) => [...prev, { type: "user", content: userPrompt }]);
    setIsLoading(true);

    try {
      const res = await apiRequest("POST", `/api/websites/${id}/debug`, { debugPrompt: userPrompt });
      const data = await res.json();

      // Show each step in chat
      data.steps?.forEach((step: string) => {
        setDebugHistory((prev) => [...prev, { type: "status", content: step }]);
      });

      // Update local code
      setCurrentCode({
        html: data.htmlCode,
        css: data.cssCode,
        js: data.jsCode,
      });

      // Refetch to sync with database
      await refetch();
    } catch (error: any) {
      const message = error?.message || error?.error || "Failed to debug code";
      toast({
        title: "Error",
        description: message,
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleCopyCode = () => {
    const code = activeTab === "html" ? currentCode.html : activeTab === "css" ? currentCode.css : currentCode.js;
    navigator.clipboard.writeText(code);
    toast({
      title: "Copied",
      description: `${activeTab.toUpperCase()} code copied to clipboard`,
    });
  };

  const handleClearHistory = () => {
    setDebugHistory([]);
    setDebugPrompt("");
  };

  if (!id) {
    return (
      <div className="min-h-screen bg-background">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <Card className="p-8 text-center text-muted-foreground">
            <p>Website not found</p>
            <Button variant="outline" className="mt-4" onClick={() => setLocation("/website-generator")}>
              Back to Generator
            </Button>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Header */}
      <div className="border-b border-border/50 bg-background/50 backdrop-blur-sm sticky top-0 z-10">
        <div className="max-w-6xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLocation("/website-generator")}
              data-testid="button-back"
            >
              <ChevronLeft className="h-5 w-5" />
            </Button>
            <h1 className="text-2xl font-bold text-center flex-1">Debug Mode</h1>
            <div className="w-10" />
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-6xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 flex-1 flex flex-col gap-4">
        {websiteLoading ? (
          <Card className="p-12 text-center flex-1 flex items-center justify-center">
            <Loader2 className="h-8 w-8 animate-spin mx-auto" />
          </Card>
        ) : (
          <>
            {/* Website Info */}
            <Card className="p-4">
              <h2 className="text-lg font-semibold mb-1">{website?.title}</h2>
              <p className="text-sm text-muted-foreground">{website?.description}</p>
            </Card>

            {/* Main Grid: Chat + Code Editor */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 flex-1 min-h-0">
              {/* Chat Panel */}
              <Card className="flex flex-col overflow-hidden">
                {/* Chat Messages */}
                <div
                  ref={setScrollRef}
                  className="flex-1 overflow-y-auto p-4 space-y-3"
                  data-testid="debug-messages-container"
                >
                  {debugHistory.length === 0 ? (
                    <div className="h-full flex items-center justify-center text-center text-muted-foreground">
                      <div>
                        <Zap className="h-12 w-12 mx-auto mb-4 opacity-50" />
                        <p>Ask LEARNORY AI to debug or improve your code</p>
                        <p className="text-xs mt-2">
                          Examples: "Add a button click handler", "Make the text responsive", "Fix the layout"
                        </p>
                      </div>
                    </div>
                  ) : (
                    debugHistory.map((msg, idx) => (
                      <div
                        key={idx}
                        className={`flex gap-3 ${msg.type === "user" ? "justify-end" : "justify-start"}`}
                        data-testid={`debug-message-${idx}`}
                      >
                        <div
                          className={`max-w-[80%] p-3 rounded-lg ${
                            msg.type === "user"
                              ? "bg-primary text-primary-foreground"
                              : "bg-yellow-100/20 dark:bg-yellow-900/20 text-foreground border border-yellow-300/30"
                          }`}
                        >
                          <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                        </div>
                      </div>
                    ))
                  )}
                  {isLoading && (
                    <div className="flex gap-3 justify-start">
                      <div className="bg-muted p-3 rounded-lg">
                        <Loader2 className="h-4 w-4 animate-spin" />
                      </div>
                    </div>
                  )}
                </div>

                {/* Input Area */}
                <div className="border-t p-4 space-y-3">
                  <Textarea
                    placeholder="Ask LEARNORY to debug, fix issues, or improve your code..."
                    value={debugPrompt}
                    onChange={(e) => setDebugPrompt(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" && e.ctrlKey) {
                        handleSubmit();
                      }
                    }}
                    className="resize-none min-h-[80px]"
                    data-testid="input-debug-prompt"
                  />
                  <div className="flex gap-2">
                    <Button
                      onClick={handleSubmit}
                      disabled={!debugPrompt.trim() || isLoading}
                      className="flex-1 hover-elevate active-elevate-2"
                      data-testid="button-submit-debug"
                    >
                      {isLoading ? (
                        <>
                          <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                          Debugging...
                        </>
                      ) : (
                        <>
                          <Send className="h-4 w-4 mr-2" />
                          Ask LEARNORY
                        </>
                      )}
                    </Button>
                    <Button
                      variant="outline"
                      onClick={handleClearHistory}
                      disabled={debugHistory.length === 0}
                      className="hover-elevate active-elevate-2"
                      data-testid="button-clear-history"
                    >
                      Clear
                    </Button>
                  </div>
                </div>
              </Card>

              {/* Code Editor Panel */}
              <Card className="flex flex-col overflow-hidden">
                {/* Tabs */}
                <div className="flex border-b bg-muted/50 p-2 gap-1">
                  {(["html", "css", "js"] as const).map((tab) => (
                    <Button
                      key={tab}
                      size="sm"
                      variant={activeTab === tab ? "default" : "ghost"}
                      onClick={() => setActiveTab(tab)}
                      className="flex-1"
                      data-testid={`tab-${tab}`}
                    >
                      {tab.toUpperCase()}
                    </Button>
                  ))}
                </div>

                {/* Code Display */}
                <div className="flex-1 overflow-auto p-4">
                  <pre className="text-sm bg-black/5 dark:bg-white/5 p-4 rounded-lg overflow-auto font-mono whitespace-pre-wrap break-words max-h-full">
                    <code>
                      {activeTab === "html"
                        ? currentCode.html
                        : activeTab === "css"
                          ? currentCode.css
                          : currentCode.js}
                    </code>
                  </pre>
                </div>

                {/* Copy Button */}
                <div className="border-t p-3">
                  <Button
                    size="sm"
                    variant="outline"
                    className="w-full hover-elevate active-elevate-2"
                    onClick={handleCopyCode}
                    data-testid="button-copy-code"
                  >
                    <Copy className="h-4 w-4 mr-2" />
                    Copy {activeTab.toUpperCase()} Code
                  </Button>
                </div>
              </Card>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

client/src/pages/ImageGenAdvanced.tsx.content:
import { useState } from "react";
import { useAuth } from "@/hooks/useAuth";
import { useMutation, useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { ThemeToggle } from "@/components/ThemeToggle";
import { Link } from "wouter";
import {
  ArrowLeft,
  Image as ImageIcon,
  Settings,
  Download,
  Trash2,
  Wand2,
  Loader2,
  History,
  Edit2,
  RefreshCw,
} from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

export default function ImageGenAdvanced() {
  const { user, isLoading: authLoading } = useAuth();
  const { toast } = useToast();
  const [prompt, setPrompt] = useState("");
  const [selectedStyle, setSelectedStyle] = useState("photorealistic");
  const [aspectRatio, setAspectRatio] = useState("1024x1024");
  const [resolution, setResolution] = useState("1024");

  const handleDeleteImage = async (imageId: string) => {
    try {
      await apiRequest("DELETE", `/api/generated-images/${imageId}`);
      queryClient.invalidateQueries({ queryKey: ["/api/generated-images"] });
      toast({ title: "Image deleted", description: "Image removed from history" });
    } catch (error) {
      toast({ title: "Error", description: "Failed to delete image", variant: "destructive" });
    }
  };

  const { data: generatedImages = [], isLoading: imagesLoading } = useQuery<any[]>({
    queryKey: ["/api/generated-images"],
    enabled: !!user,
  });

  const generateImageMutation = useMutation({
    mutationFn: async (data: { prompt: string; style: string; resolution: string }) => {
      const response = await apiRequest("POST", "/api/generate-image", data);
      return response.json();
    },
    onSuccess: (data) => {
      toast({ title: "Image generated!", description: "Your image has been created." });
      queryClient.invalidateQueries({ queryKey: ["/api/generated-images"] });
      setPrompt("");
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to generate image", variant: "destructive" });
    },
  });

  if (authLoading || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-pulse">Loading...</div>
      </div>
    );
  }

  const styles = [
    { id: "photorealistic", name: "Photorealistic", icon: "📸" },
    { id: "illustrated", name: "Illustrated", icon: "🎨" },
    { id: "sketch", name: "Sketch", icon: "✏️" },
    { id: "3d", name: "3D Render", icon: "🎮" },
    { id: "watercolor", name: "Watercolor", icon: "🌊" },
    { id: "neon", name: "Neon", icon: "⚡" },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5">
      {/* Header */}
      <header className="sticky top-0 z-50 backdrop-blur-xl bg-background/80 border-b border-primary/10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-4">
              <Button variant="ghost" size="icon" asChild className="hover-elevate" data-testid="button-back">
                <Link href="/dashboard">
                  <ArrowLeft className="h-5 w-5" />
                </Link>
              </Button>
              <div className="flex items-center gap-3">
                <ImageIcon className="h-6 w-6 text-primary" />
                <h1 className="text-2xl font-bold">Image Generator</h1>
              </div>
            </div>
            <ThemeToggle />
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid lg:grid-cols-2 gap-8">
          {/* Generator Panel */}
          <Card className="hover-elevate" data-testid="card-image-generator">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Wand2 className="h-5 w-5 text-primary" />
                Create New Image
              </CardTitle>
            </CardHeader>

            <CardContent className="space-y-6">
              {/* Prompt Input */}
              <div className="space-y-2">
                <label className="text-sm font-semibold">Describe your image</label>
                <Textarea
                  placeholder="A futuristic city at night with neon lights, cyberpunk style..."
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  rows={4}
                  className="resize-none"
                  data-testid="textarea-image-prompt"
                />
              </div>

              {/* Style Templates */}
              <div className="space-y-2">
                <label className="text-sm font-semibold">Style</label>
                <div className="grid grid-cols-3 gap-2">
                  {styles.map((style) => (
                    <Button
                      key={style.id}
                      variant={selectedStyle === style.id ? "default" : "outline"}
                      size="sm"
                      onClick={() => setSelectedStyle(style.id)}
                      className="hover-elevate h-auto py-3"
                      data-testid={`button-style-${style.id}`}
                    >
                      <div className="text-center">
                        <div className="text-2xl mb-1">{style.icon}</div>
                        <p className="text-xs">{style.name}</p>
                      </div>
                    </Button>
                  ))}
                </div>
              </div>

              {/* Aspect Ratio */}
              <div className="space-y-2">
                <label className="text-sm font-semibold">Aspect Ratio</label>
                <div className="grid grid-cols-2 gap-2">
                  {["1024x1024", "1024x768", "768x1024"].map((ratio) => (
                    <Button
                      key={ratio}
                      variant={aspectRatio === ratio ? "default" : "outline"}
                      size="sm"
                      onClick={() => setAspectRatio(ratio)}
                      className="hover-elevate"
                      data-testid={`button-ratio-${ratio.replace("x", "-")}`}
                    >
                      {ratio}
                    </Button>
                  ))}
                </div>
              </div>

              {/* Resolution */}
              <div className="space-y-2">
                <label className="text-sm font-semibold">Resolution</label>
                <div className="grid grid-cols-2 gap-2">
                  {["512", "768", "1024"].map((res) => (
                    <Button
                      key={res}
                      variant={resolution === res ? "default" : "outline"}
                      size="sm"
                      onClick={() => setResolution(res)}
                      className="hover-elevate"
                      data-testid={`button-resolution-${res}`}
                    >
                      {res}p
                    </Button>
                  ))}
                </div>
              </div>

              {/* Generate Button */}
              <Button
                size="lg"
                className="w-full hover-elevate"
                onClick={() => generateImageMutation.mutate({ prompt, style: selectedStyle, resolution })}
                disabled={generateImageMutation.isPending || !prompt}
                data-testid="button-generate-image"
              >
                {generateImageMutation.isPending ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Generating...
                  </>
                ) : (
                  <>
                    <Wand2 className="h-4 w-4 mr-2" />
                    Generate Image
                  </>
                )}
              </Button>
            </CardContent>
          </Card>

          {/* History & Preview */}
          <div className="space-y-6">
            {/* Preview of last generated */}
            {generatedImages.length > 0 && (
              <Card className="overflow-hidden hover-elevate" data-testid="card-preview">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <History className="h-5 w-5 text-primary" />
                    Latest Image
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="w-full aspect-square bg-secondary/50 rounded-lg overflow-hidden">
                    <img
                      src={generatedImages[0].imageUrl}
                      alt={generatedImages[0].prompt}
                      className="w-full h-full object-cover"
                      data-testid="img-preview"
                    />
                  </div>
                  <div>
                    <p className="text-sm font-medium mb-3">{generatedImages[0].prompt}</p>
                    <div className="flex gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        className="flex-1 hover-elevate"
                        asChild
                        data-testid="button-download-preview"
                      >
                        <a href={generatedImages[0].imageUrl} download>
                          <Download className="h-4 w-4 mr-2" />
                          Download
                        </a>
                      </Button>
                      <Button
                        variant="destructive"
                        size="sm"
                        className="hover-elevate"
                        onClick={() => handleDeleteImage(generatedImages[0].id)}
                        data-testid="button-delete-preview"
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Image History */}
            <Card data-testid="card-history">
              <CardHeader>
                <CardTitle className="flex items-center justify-between">
                  <span className="flex items-center gap-2">
                    <History className="h-5 w-5 text-primary" />
                    History
                  </span>
                  <Badge>{generatedImages.length}</Badge>
                </CardTitle>
              </CardHeader>
              <CardContent>
                {imagesLoading ? (
                  <div className="text-center py-6">
                    <Loader2 className="h-6 w-6 animate-spin mx-auto text-primary" />
                  </div>
                ) : generatedImages.length === 0 ? (
                  <p className="text-sm text-muted-foreground text-center py-6">
                    No images generated yet. Create your first image to get started!
                  </p>
                ) : (
                  <div className="grid grid-cols-2 gap-2 max-h-96 overflow-y-auto">
                    {generatedImages.map((img: any) => (
                      <div key={img.id} className="group relative overflow-hidden rounded-lg hover-elevate" data-testid={`card-history-item-${img.id}`}>
                        <img
                          src={img.imageUrl}
                          alt={img.prompt}
                          className="w-full h-24 object-cover"
                        />
                        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                          <Button size="sm" variant="ghost" className="hover-elevate" data-testid={`button-edit-${img.id}`}>
                            <Edit2 className="h-4 w-4" />
                          </Button>
                          <Button size="sm" variant="destructive" className="hover-elevate" onClick={() => handleDeleteImage(img.id)} data-testid={`button-delete-${img.id}`}>
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </main>
    </div>
  );
}

client/src/pages/SettingsPanel.tsx.content:
import { useState, useEffect } from "react";
import { useAuth } from "@/hooks/useAuth";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { ThemeToggle } from "@/components/ThemeToggle";
import { useTheme } from "@/components/ThemeProvider";
import { Link } from "wouter";
import { useToast } from "@/hooks/use-toast";
import {
  ArrowLeft,
  Settings,
  Moon,
  Sun,
  Palette,
  Lock,
  Bell,
  Download,
  Zap,
  Keyboard,
  Volume2,
} from "lucide-react";
import { useVoice, AVAILABLE_VOICES } from "@/lib/useVoice";

export default function SettingsPanel() {
  const { user, isLoading: authLoading } = useAuth();
  const { selectedVoice, setSelectedVoice, speak } = useVoice();
  const { theme, setTheme } = useTheme();
  const { toast } = useToast();
  const [notifications, setNotifications] = useState(() => {
    const saved = localStorage.getItem("notifications");
    return saved ? JSON.parse(saved) : { messages: true, suggestions: true, updates: false };
  });
  const [dataCollection, setDataCollection] = useState(() => {
    return localStorage.getItem("dataCollection") !== "false";
  });
  const [sharedLearning, setSharedLearning] = useState(() => {
    return localStorage.getItem("sharedLearning") !== "false";
  });

  useEffect(() => {
    localStorage.setItem("notifications", JSON.stringify(notifications));
  }, [notifications]);

  useEffect(() => {
    localStorage.setItem("dataCollection", String(dataCollection));
  }, [dataCollection]);

  useEffect(() => {
    localStorage.setItem("sharedLearning", String(sharedLearning));
  }, [sharedLearning]);

  if (authLoading || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-pulse text-muted-foreground">Loading...</div>
      </div>
    );
  }

  const settings = [
    {
      title: "Appearance",
      icon: Palette,
      items: [
        {
          label: "Theme",
          description: "Light, Dark, or Neon mode",
          component: (
            <div className="flex gap-2" data-testid="select-theme">
              {["light", "dark", "neon"].map((t) => (
                <Button
                  key={t}
                  size="sm"
                  variant={theme === t ? "default" : "outline"}
                  onClick={() => setTheme(t as "light" | "dark" | "neon")}
                  className="hover-elevate"
                  data-testid={`button-theme-${t}`}
                >
                  {t.charAt(0).toUpperCase() + t.slice(1)}
                </Button>
              ))}
            </div>
          ),
        },
      ],
    },
    {
      title: "Notifications",
      icon: Bell,
      items: [
        {
          label: "Message Notifications",
          description: "Get notified when you receive messages",
          component: (
            <Switch
              checked={notifications.messages}
              onCheckedChange={(val) =>
                setNotifications({ ...notifications, messages: val })
              }
              data-testid="switch-message-notifications"
            />
          ),
        },
        {
          label: "AI Suggestions",
          description: "Receive suggestions and recommendations",
          component: (
            <Switch
              checked={notifications.suggestions}
              onCheckedChange={(val) =>
                setNotifications({ ...notifications, suggestions: val })
              }
              data-testid="switch-suggestion-notifications"
            />
          ),
        },
        {
          label: "Product Updates",
          description: "Learn about new features",
          component: (
            <Switch
              checked={notifications.updates}
              onCheckedChange={(val) =>
                setNotifications({ ...notifications, updates: val })
              }
              data-testid="switch-update-notifications"
            />
          ),
        },
      ],
    },
    {
      title: "Privacy & Data",
      icon: Lock,
      items: [
        {
          label: "Data Collection",
          description: "Allow LERNORY to analyze learning patterns",
          component: (
            <Switch
              checked={dataCollection}
              onCheckedChange={(val) => setDataCollection(val)}
              data-testid="switch-data-collection"
            />
          ),
        },
        {
          label: "Shared Learning",
          description: "Share insights with teachers (if student)",
          component: (
            <Switch
              checked={sharedLearning}
              onCheckedChange={(val) => setSharedLearning(val)}
              data-testid="switch-shared-learning"
            />
          ),
        },
      ],
    },
    {
      title: "Voice Settings",
      icon: Volume2,
      items: [
        {
          label: "Select Voice",
          description: "Choose your preferred AI voice for reading responses",
          component: (
            <div className="flex flex-col gap-2" data-testid="select-voice">
              <select
                value={selectedVoice}
                onChange={(e) => {
                  setSelectedVoice(e.target.value);
                  speak("Voice changed successfully");
                }}
                className="px-3 py-2 rounded-md border border-border bg-background text-foreground"
                data-testid="select-voice-dropdown"
              >
                {AVAILABLE_VOICES.map((voice) => (
                  <option key={voice.name} value={voice.name}>
                    {voice.name}
                    {voice.nigerian ? " 🇳🇬" : ""}
                  </option>
                ))}
              </select>
              <Button
                size="sm"
                variant="outline"
