                  </>
                ) : (
                  "Generate Website"
                )}
              </Button>
            </Card>

            {/* Websites List */}
            <Card className="p-4 space-y-2">
              <h2 className="font-semibold text-sm mb-3">Your Websites ({websites.length})</h2>
