// Motivation Coach
// Provides personalized encouragement and learning insights

export interface MotivationalMessage {
  message: string;
  type: "encouragement" | "reminder" | "tip" | "achievement" | "warning";
  icon: string;
}

/**
 * Generate motivational message based on user performance
 */
export function generateMotivationalMessage(userStats: any): MotivationalMessage {
  const { streak, averageScore, totalQuestionsAttempted, weakTopics, strongTopics, lastStudyTime } = userStats;

  // Streak motivation
  if (streak >= 30) {
    return {
      message: `🔥 You've maintained a ${streak}-day study streak! You're unstoppable. Keep crushing it!`,
      type: "achievement",
      icon: "⚡",
    };
  } else if (streak >= 7) {
    return {
      message: `🎯 ${streak} days of consistency! You're building real momentum. Just ${30 - streak} more days for legend status!`,
      type: "encouragement",
      icon: "🚀",
    };
  }

  // Performance-based motivation
  if (averageScore >= 90) {
    return {
      message: `💯 Your ${averageScore}% average score is outstanding! You're ready for the exam. Keep focused!`,
      type: "achievement",
      icon: "🏆",
    };
  } else if (averageScore >= 75) {
    return {
      message: `✨ You're at ${averageScore}% - solid progress! One more push to reach 90%+`,
      type: "encouragement",
      icon: "💪",
    };
  } else if (averageScore >= 60) {
    return {
      message: `📈 At ${averageScore}%, you're on the right track. Focus on your weak areas: ${weakTopics.slice(0, 2).join(", ")}`,
      type: "tip",
      icon: "🎯",
    };
  } else {
    return {
      message: `💡 You're at ${averageScore}%. Don't worry - increased focus on ${weakTopics[0]} will boost your score quickly!`,
      type: "reminder",
      icon: "🌟",
    };
  }
}

/**
 * Generate daily study reminder
 */
export function generateDailyReminder(time: Date, userStats: any): MotivationalMessage {
  const hour = time.getHours();
  const { streak, studyGoalToday } = userStats;

  let message = "";
  let icon = "";

  if (hour < 7) {
    message = `🌅 Early bird! Starting your day strong. Let's get ${studyGoalToday} minutes of quality study in!`;
    icon = "✨";
  } else if (hour < 12) {
    message = `⏰ Good morning! Don't break your ${streak}-day streak. Study session time!`;
    icon = "📚";
  } else if (hour < 17) {
    message = `☀️ Afternoon boost needed! Get some revision done to stay on track.`;
    icon = "💪";
  } else if (hour < 21) {
    message = `🎯 Evening push! Solidify today's learning with a quick ${studyGoalToday}-minute session.`;
    icon = "🔥";
  } else {
    message = `🌙 Night owl studying? Great dedication! Don't overdo it - get some rest too!`;
    icon = "😴";
  }

  return {
    message,
    type: "reminder",
    icon,
  };
}

/**
 * Generate exam-specific encouragement
 */
export function generateExamEncouragement(daysUntilExam: number, averageScore: number): MotivationalMessage {
  if (daysUntilExam <= 1) {
    return {
      message: `🎯 EXAM DAY IS HERE! You've prepared well. Trust your training, stay calm, and give your best. You've got this! 💯`,
      type: "encouragement",
      icon: "🏆",
    };
  } else if (daysUntilExam <= 3) {
    return {
      message: `⚡ ${daysUntilExam} days to the exam! Final touches: review weak topics, get good sleep, trust your preparation!`,
      type: "reminder",
      icon: "🚀",
    };
  } else if (daysUntilExam <= 7) {
    return {
      message: `📚 Final week push! You're at ${averageScore}%. One more week of focus can get you to 90%+!`,
      type: "encouragement",
      icon: "💪",
    };
  } else if (daysUntilExam <= 14) {
    return {
      message: `🎓 Two weeks out. ${averageScore}% is great, but let's aim higher! Intensive review time!`,
      type: "tip",
      icon: "🎯",
    };
  } else {
    return {
      message: `You have ${daysUntilExam} days. Your current score is ${averageScore}%. Keep consistent study to reach 350+ on JAMB!`,
      type: "reminder",
      icon: "📈",
    };
  }
}

/**
 * Generate performance-based tips
 */
export function generatePerformanceTip(subject: string, weakAreas: string[]): MotivationalMessage {
  const tips: Record<string, string> = {
    Mathematics: "Focus on formula derivations, not just memorization. Practice past questions with full working shown.",
    Physics: "Draw diagrams for every problem. Physics is about understanding concepts, not just calculations.",
    Chemistry: "Balance equations step-by-step. Know oxidation states. Practice reaction types repeatedly.",
    Biology: "Draw and label diagrams. Learn processes in sequence. Connect structure to function.",
    English: "Read widely. Practice essay structure (intro → 3 points → conclusion). Proofread your work.",
    Government: "Make mind maps of institutions. Know processes and stakeholders. Connect to Nigerian context.",
    Commerce: "Master double-entry bookkeeping. Understand accounting standards. Practice calculations.",
  };

  const tip = tips[subject] || "Consistent practice of past questions is your best strategy!";

  return {
    message: `💡 TIP FOR ${subject.toUpperCase()}: ${tip}`,
    type: "tip",
    icon: "🎯",
  };
}

/**
 * Celebrate milestones
 */
export function celebrateMilestone(achievement: string): MotivationalMessage {
  const celebrations: Record<string, MotivationalMessage> = {
    "perfect_quiz": {
      message: `🌟 PERFECT SCORE! 100% on this quiz! You've truly mastered this topic!`,
      type: "achievement",
      icon: "🏆",
    },
    "first_week": {
      message: `🎉 You completed your first full week of study! Consistency is key - keep it up!`,
      type: "achievement",
      icon: "💫",
    },
    "subject_mastery": {
      message: `🧠 Subject Mastery Unlocked! You're now an expert in this area!`,
      type: "achievement",
      icon: "⭐",
    },
    "level_up": {
      message: `🚀 LEVEL UP! You've reached a new level. Your efforts are paying off!`,
      type: "achievement",
      icon: "⬆️",
    },
    "badge_earned": {
      message: `🎖️ BADGE EARNED! Another achievement to add to your collection!`,
      type: "achievement",
      icon: "🏅",
    },
  };

  return celebrations[achievement] || {
    message: `🎉 Great achievement! Keep this momentum going!`,
    type: "achievement",
    icon: "✨",
  };
}

server/mockExamEngine.ts.content:
// Mock Exam Engine
// Generates auto-marked mock exams with performance tracking

export interface MockExamQuestion {
  id: string;
  subject: string;
  topic: string;
  difficulty: "easy" | "medium" | "hard";
  questionText: string;
  questionType: "mcq" | "theory" | "essay";
  options?: string[];
  correctAnswer: string | string[];
  explanation: string;
  difficultyScore: number; // 1-5
}

export interface MockExamResult {
  examId: string;
  userId: string;
  subject: string;
  totalQuestions: number;
  correctAnswers: number;
  wrongAnswers: number;
  skipped: number;
  score: number; // percentage
  timeSpent: number; // minutes
  performance: {
    easyAccuracy: number;
    mediumAccuracy: number;
    hardAccuracy: number;
  };
  weakTopics: string[];
  strongTopics: string[];
  recommendations: string[];
}

/**
 * Generate a mock exam for a subject
 */
export function generateMockExam(
  subject: string,
  difficulty: "easy" | "medium" | "hard" = "medium",
  questionCount: number = 20
): MockExamQuestion[] {
  // This would be expanded with a full question bank in production
  const questionBank: Record<string, MockExamQuestion[]> = {
    mathematics: [
      {
        id: "math-001",
        subject: "mathematics",
        topic: "Quadratic Equations",
        difficulty: "medium",
        questionType: "mcq",
        questionText: "Solve the equation x² + 5x + 6 = 0",
        options: ["x = -2 or x = -3", "x = 2 or x = 3", "x = 1 or x = -6", "x = -1 or x = 6"],
        correctAnswer: "x = -2 or x = -3",
        explanation: "Using factorization: (x + 2)(x + 3) = 0, so x = -2 or x = -3",
        difficultyScore: 2,
      },
      {
        id: "math-002",
        subject: "mathematics",
        topic: "Algebra",
        difficulty: "hard",
        questionType: "theory",
        questionText: "Prove that for any integer n, n² + n is always even",
        options: [],
        correctAnswer: "Case 1: If n is even, n = 2k, then n² + n = 4k² + 2k = 2(2k² + k), which is even.\nCase 2: If n is odd, n = 2k+1, then n² + n = (2k+1)² + (2k+1) = 4k² + 4k + 1 + 2k + 1 = 4k² + 6k + 2 = 2(2k² + 3k + 1), which is even.",
        explanation: "Proof by cases - covers both even and odd integers.",
        difficultyScore: 4,
      },
    ],
    physics: [
      {
        id: "phys-001",
        subject: "physics",
        topic: "Motion",
        difficulty: "medium",
        questionType: "mcq",
        questionText: "An object is thrown upward with velocity 20 m/s. What is its maximum height? (g = 10 m/s²)",
        options: ["10 m", "20 m", "30 m", "40 m"],
        correctAnswer: "20 m",
        explanation: "Using v² = u² - 2gs, at max height v = 0, so 0 = 400 - 2(10)s, giving s = 20 m",
        difficultyScore: 3,
      },
    ],
    chemistry: [
      {
        id: "chem-001",
        subject: "chemistry",
        topic: "Chemical Bonding",
        difficulty: "medium",
        questionType: "mcq",
        questionText: "Which of these molecules is non-polar?",
        options: ["CO₂", "HCl", "H₂O", "NH₃"],
        correctAnswer: "CO₂",
        explanation: "CO₂ is linear and symmetric, so dipoles cancel out. HCl, H₂O, NH₃ are all polar.",
        difficultyScore: 2,
      },
    ],
  };

  const subjectQuestions = questionBank[subject.toLowerCase()] || [];
  return subjectQuestions.slice(0, questionCount);
}

/**
 * Auto-mark an exam
 */
export function markExam(
  userAnswers: Record<string, string>,
  questions: MockExamQuestion[]
): MockExamResult {
  let correctCount = 0;
  let wrongCount = 0;
  let skippedCount = 0;
  const topicPerformance: Record<string, { correct: number; total: number }> = {};
  const weakTopics: string[] = [];
  const strongTopics: string[] = [];

  questions.forEach((q) => {
    const userAnswer = userAnswers[q.id];

    if (!userAnswer) {
      skippedCount++;
      return;
    }

    // Initialize topic tracking
    if (!topicPerformance[q.topic]) {
      topicPerformance[q.topic] = { correct: 0, total: 0 };
    }
    topicPerformance[q.topic].total++;

    const isCorrect = userAnswer.toLowerCase() === q.correctAnswer.toLowerCase();
    if (isCorrect) {
      correctCount++;
      topicPerformance[q.topic].correct++;
    } else {
      wrongCount++;
    }
  });

  // Analyze weak and strong topics
  Object.entries(topicPerformance).forEach(([topic, perf]) => {
    const accuracy = (perf.correct / perf.total) * 100;
    if (accuracy < 60) {
      weakTopics.push(topic);
    } else if (accuracy >= 80) {
      strongTopics.push(topic);
    }
  });

  const score = (correctCount / (questions.length - skippedCount)) * 100;

  // Calculate performance by difficulty
  const byDifficulty = {
    easy: questions.filter((q) => q.difficulty === "easy").length,
    medium: questions.filter((q) => q.difficulty === "medium").length,
    hard: questions.filter((q) => q.difficulty === "hard").length,
  };

  return {
    examId: "exam-" + Date.now(),
    userId: "user-placeholder",
    subject: questions[0]?.subject || "general",
    totalQuestions: questions.length,
    correctAnswers: correctCount,
    wrongAnswers: wrongCount,
    skipped: skippedCount,
    score,
    timeSpent: 0, // Would be calculated from timestamps
    performance: {
      easyAccuracy: 95, // Placeholder - would calculate from actual answers
      mediumAccuracy: score,
      hardAccuracy: score > 50 ? score - 20 : 30,
    },
    weakTopics,
    strongTopics,
    recommendations: generateRecommendations(weakTopics, score),
  };
}

/**
 * Generate personalized recommendations based on exam performance
 */
export function generateRecommendations(weakTopics: string[], score: number): string[] {
  const recommendations: string[] = [];

  if (score >= 90) {
    recommendations.push("Excellent performance! Maintain this standard and tackle advanced problems.");
  } else if (score >= 75) {
    recommendations.push("Good job! Focus on solidifying weak areas to reach 90%+");
  } else if (score >= 60) {
    recommendations.push("Decent progress. Increase practice on weak topics to improve score.");
  } else {
    recommendations.push("You need more practice. Revisit fundamentals and practice daily.");
  }

  weakTopics.forEach((topic) => {
    recommendations.push(`Master "${topic}" - this is critical for your exam success`);
  });

  return recommendations;
}

/**
 * Calculate prediction for final exam score
 */
export function predictFinalScore(
  currentMockScores: number[],
  daysUntilExam: number
): { prediction: number; range: [number, number] } {
  if (currentMockScores.length === 0) {
    return { prediction: 50, range: [40, 60] };
  }

  const average = currentMockScores.reduce((a, b) => a + b) / currentMockScores.length;
  const trend = currentMockScores.length > 1 
    ? (currentMockScores[currentMockScores.length - 1] - currentMockScores[0]) / (currentMockScores.length - 1)
    : 0;

  // Project based on trend
  const projectedScore = average + trend * (daysUntilExam / 7);
  const cappedScore = Math.min(100, Math.max(0, projectedScore));

  return {
    prediction: Math.round(cappedScore),
    range: [Math.max(0, Math.round(cappedScore - 10)), Math.min(100, Math.round(cappedScore + 10))],
  };
}

